  policy_name     = "route53-query-logging-policy"
  policy_document = <<POLICY_DOCUMENT
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Principal": {
        "Service": "route53.amazonaws.com"
      },
      "Action": [
        "logs:CreateLogStream",
        "logs:PutLogEvents",
        "logs:DescribeLogStreams"
      ],
      "Resource": [
        "${aws_cloudwatch_log_group.route53_log_group.arn}:*"
      ]
    }
  ]
}
POLICY_DOCUMENT
}

