resource "random_password" "db" {
  length  = 16
  special = false
}

resource "aws_route53_record" "weighted_routing" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "main.example.com"
  type    = "A"

  alias {
    name                   = aws_db_instance.primary.endpoint
    zone_id                = aws_db_instance.primary.allocated_storage_id
    evaluate_target_health = true
  }

  set_identifier = "weighted-route"

  failover_routing_policy {
    failover_criteria {
      type           = "HEALTH"
      health_threshold = 1
    }
  }

  health_check_id = aws_route53_health_check.primary.id
}

resource "aws_route53_health_check" "primary" {
  fqdn             = aws_db_instance.primary.endpoint
  type             = "HTTPS"
  resource_path    = "/"
  fully_qualified_domain_name = aws_db_instance.primary.endpoint
  port             = 443
}

resource "aws_route53_record" "weighted_replica_1" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "main.example.com"
