  }
  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBPassword"
    value     = aws_db_instance.my_db.password
  }
}

resource "aws_elastic_beanstalk_application_version" "app_version" {
  name        = "app-version-${random_id.suffix.hex}"
  application = aws_elastic_beanstalk_application.app.name
  source_ip   = "0.0.0.0/0"
  auto_create_application = true
  # Add your application source code here, e.g., from S3 or GitHub
}

resource "aws_elastic_beanstalk_application_version" "app_version_snapshot" {
  name        = "app-version-snapshot-${random_id.suffix.hex}"
  application = aws_elastic_beanstalk_application.app.name
  source_ip   = "0.0.0.0/0"
  auto_create_application = true
