  depends_on = [aws_db_instance.my_db]
}

resource "aws_db_snapshot" "pre_deployment_snapshot" {
  db_snapshot_identifier = "pre-deployment-snapshot-${random_id.suffix.hex}"
  db_instance_identifier = aws_db_instance.my_db.id
  depends_on = [aws_db_instance.my_db]
}
