  name    = "example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv_us_east.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv_us_east.cname_zone_id
    evaluate_target_health = true
    failover_routing_policy {
      failover_criteria {
        type = "HEALTH"
      }
    }
  }
}

resource "aws_route53_record" "primary_domain_fallback" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "example.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.myenv_eu_west.cname
    zone_id                = aws_elastic_beanstalk_environment.myenv_eu_west.cname_zone_id
    evaluate_target_health = true
    failover_routing_policy {
      failover_criteria {
        type = "HEALTH"
      }
    }
  }
}
