    evaluate_target_health = true
  }

  health_check_id = aws_route53_health_check.green.id
}

resource "aws_route53_health_check" "blue" {
  fqdn              = aws_elastic_beanstalk_environment.blue.cname
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30
}

resource "aws_route53_health_check" "green" {
  fqdn              = aws_elastic_beanstalk_environment.green.cname
  type              = "HTTPS"
  resource_path     = "/health"
  failure_threshold = 3
  request_interval  = 30
}

resource "aws_route53_record" "app" {
  zone_id = aws_route53_zone.app.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_route53_record.blue_healthcheck.fqdn
    zone_id                = aws_route53_record.blue_healthcheck.zone_id
    evaluate_target_health = true
    failover_routing_policy {
      type = "PRIMARY"
    }
  }
}

resource "aws_route53_record" "app_failover" {
  zone_id = aws_route53_zone.app.zone_id
  name    = "app.example.com"
  type    = "A"

  alias {
    name                   = aws_route53_record.green_healthcheck.fqdn
    zone_id                = aws_route53_record.green_healthcheck.zone_id
    evaluate_target_health = true
    failover_routing_policy {
      type = "SECONDARY"
    }
  }
}
