    fetch_submodules = true
  }
}

resource "aws_codebuild_source_repository" "github_repo" {
  identifier = "github-repo-${random_id.suffix.hex}"
  repository = "https://github.com/your-org/your-repo.git"
  type       = "GITHUB"
  auth_type  = "OAUTH"
  auth_name  = "github-oauth"
  auth_token = var.github_token # Store this securely in Terraform variables
}

resource "aws_codebuild_project" "example" {
  name          = "example-project-${random_id.suffix.hex}"
  description   = "Example CodeBuild project"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "ENV_VARIABLE_NAME"
      value = "env_variable_value"
    }
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/example-project-${random_id.suffix.hex}"
      stream_name = "build-log"
    }
    s3_logs {
      status = "DISABLED"
    }
  }

  source {
    type      = "GITHUB"
    location  = aws_codebuild_source_repository.github_repo.repository
    git_clone_depth = 0
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install --upgrade pip
            - pip install -r requirements.txt
        pre_build:
          commands:
            - echo "Pre-build scripts..."
        build:
          commands:
            - echo "Building the application..."
            - python setup.py build
        post_build:
          commands:
            - echo "Post-build scripts..."
      artifacts:
        files:
          - '**/*'
      cache:
        paths:
          - '/root/.cache/pip/**/*'
    EOT
    }
  }
}

