              "utterance" : "Reserve a flight to Paris"
            }
          ],
          "inputSlot" : {
            "name" : "Destination",
            "slotType" : "Reservation"
          },
          "outputDialog" : {
            "type" : "ConfirmIntent",
            "confirmIntent" : {
              "messageGroups" : [
                {
                  "message" : {
                    "plainTextMessage" : {
                      "value" : "Would you like to confirm your reservation to {Destination}?"
                    }
                  }
                }
              ],
              "confirmationSlot" : {
                "name" : "Confirmation",
                "slotType" : "AMAZON.YesNo"
              }
            }
          },
          "fulfillmentActivity" : {
            "type" : "ReturnIntent"
          }
        },
        {
          "name" : "CancelIntent",
          "description" : "Intent for canceling reservations",
          "sampleUtterances" : [
            {
              "utterance" : "Cancel my reservation"
            },
            {
              "utterance" : "I want to cancel"
            }
          ],
          "fulfillmentActivity" : {
            "type" : "ReturnIntent"
          }
        }
      ],
      "slots" : [
        {
          "name" : "Destination",
          "description" : "The destination for the trip",
          "slotType" : "Reservation",
          "valueElicitationSetting" : {
            "slotConstraint" : "Required",
            "promptSpecification" : {
              "maxRetries" : 5,
              "messageGroups" : [
                {
                  "message" : {
                    "plainTextMessage" : {
                      "value" : "What is your destination?"
                    }
                  }
                }
              ]
            }
          }
        },
        {
          "name" : "DepartureDate",
          "description" : "The departure date for the trip",
          "slotType" : "AMAZON.Date",
          "valueElicitationSetting" : {
            "slotConstraint" : "Required",
            "promptSpecification" : {
              "maxRetries" : 5,
              "messageGroups" : [
                {
                  "message" : {
                    "plainTextMessage" : {
                      "value" : "When would you like to depart?"
                    }
                  }
                }
              ]
            }
          }
        }
      ],
      "responseMappings" : [
        {
          "intentName" : "ReservationIntent",
          "responseContent" : {
            "messageGroups" : [
              {
                "message" : {
                  "plainTextMessage" : {
                    "value" : "Your reservation to {Destination} on {DepartureDate} has been confirmed."
                  }
                }
              }
            ]
          }
        }
      ]
    }
  })

  # Bot settings
  role_arn      = "arn:aws:iam::123456789012:role/lex-bot-role" # Replace with your IAM role ARN
  data_privacy {
    child_directed  = false
    logging_option  = "All"
    user_data_policy = "OptInRequired"
  }
  # Enable CloudWatch logging
  cloudwatch_logging_options {
    cloudwatch_log_group_arn = "arn:aws:logs:us-east-1:123456789012:log-group:/aws/lex/bots/trip-reservation-bot-${random_id.bot_suffix.hex}:log-stream:*:*"
    enable_capture               = true
  }
  # Enable voice support
  voice_settings {
    voice_id = "en-US-Elizabeth"
  }
}
