resource "aws_lex_bot" "pizza_order_bot" {
  name                = "pizza-order-bot-${random_id.suffix.hex}"
  description         = "A Lex bot for children to place pizza orders"
  idempotency_strategy = "CREATE_IF_NEW"

  lifecycle {
    prevent_destroy = false
  }

  role_arn = aws_iam_role.lex_bot_role.arn

  child_directed = true # Ensures compliance with COPPA for child-directed services

  # Intents for pizza order bot
  intent {
    name = "OrderPizzaIntent"
    sample_utterances = [
      "I want a pizza",
      "Order me a pizza",
      "Can I get a pizza?",
      "Pizza please"
    ]

    slots {
      name = "pizza_type"
      value_elicitation_setting {
        slot_constraint = "Required"
        prompt_specification {
          max_attempts = 3
          message_groups {
            en_US {
              message {
                plain_text_value = "What type of pizza would you like?"
              }
            }
          }
        }
      }
    }

    fulfillment_activity {
      type = "ReturnIntent"
      return_values {
        slot_value {
          name = "pizza_type"
          value {
            literal_value = { value = "pizza_type" }
          }
        }
      }
    }
  }

  intent {
    name = "ThankYouIntent"
    sample_utterances = [
      "Thanks",
      "Bye",
      "Goodbye"
    ]

    fulfillment_activity {
      type = "Close"
    }
  }

  intent {
    name = "HelpIntent"
    sample_utterances = [
      "Help",
      "What can you do?",
      "I need help"
    ]

    fulfillment_activity {
      type = "ReturnIntent"
      return_values {
        slot_value {
          name = "help_message"
          value {
            literal_value { value = "You can order a pizza by saying 'I want a pizza'. Then tell me the type of pizza you'd like!" }
          }
        }
      }
    }
  }
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-order-bot-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_cloudwatch_log_group" "lex_log_group" {
  name              = "/aws/lex/pizza-order-bot-${random_id.suffix.hex}"
  retention_in_days = 7
}

