  byte_length = 4
}

resource "aws_lex_bot" "pizza_order_bot" {
  name        = "pizza-order-bot-${random_id.suffix.hex}"
  description = "Bot for ordering pizza with NLU confidence threshold of 0.5"
  role_arn    = aws_iam_role.lex_bot_role.arn

  nlu_intent_confidence_threshold = 0.5

  lifecycle {
    ignore_changes = [version]
  }
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex-pizza-order-bot-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonLexBotServiceRolePolicy"
}
