  description = "Example bot for Lex V2"
  role_arn    = aws_iam_role.lex_bot_role.arn
  idempotency_key {
    name = "example-bot-idempotency-key"
  }
  tags = {
    Environment = "test"
  }
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex-bot-role-${random_id.bot_suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lexv2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_lexv2_models_slot_type" "example_slot_type" {
  name        = "example-slot-type"
  bot_id      = aws_lexv2_models_bot.example_bot.id
  description = "Example slot type for Lex V2"
  value_elimination_settings {
    elimination_strategy = "ELIMINATE_ALL"
  }
}

resource "aws_lexv2_models_intent" "example_intent" {
  name        = "example-intent"
  bot_id      = aws_lexv2_models_bot.example_bot.id
  description = "Example intent for Lex V2"
  sample_utterances = [
    "Hello",
    "Hi there"
  ]
  parent_intent_signature {
    name = "FallbackIntent"
  }
}

resource "aws_lexv2_models_dialog_code_hook" "example_dialog_hook" {
  name        = "example-dialog-hook"
  bot_id      = aws_lexv2_models_bot.example_bot.id
  description = "Example dialog code hook for Lex V2"
  invocation_router_arn = aws_lambda_function.lex_dialog_hook.arn
}

resource "aws_lambda_function" "lex_dialog_hook" {
  function_name = "lex-dialog-hook-${random_id.bot_suffix.hex}"
  runtime       = "nodejs14.x"
  handler       = "index.handler"
  role          = aws_iam_role.lambda_exec.arn
  filename      = "lambda_function.zip" # Replace with your lambda function zip file
  depends_on    = [aws_iam_role_policy_attachment.lambda_basic_execution]
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda-exec-role-${random_id.bot_suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

