  bot_name = "AmazonConnectBot" # Default bot name for Amazon Connect

  # Required if associating with a specific instance
  instance_arn = "arn:aws:connect:${var.aws_region}:${data.aws_caller_identity.current.account_id}:instance/${var.connect_instance_id}"

  # Optional: Specify a custom name for the association
  name = "connect-bot-association-${random_id.suffix.hex}"

  # Optional: Configure the bot's permissions
