terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_s3_bucket" "januaryseventh" {
  bucket = "januaryseventh"
}

resource "aws_opensearch_domain" "test_cluster" {
  domain_name = "es-test-3"

  cluster_config {
    instance_count         = 2
    zone_awareness_enabled = true
    instance_type          = "m4.large.search"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }
}

data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name               = "firehose_test_role"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

data "aws_iam_policy_document" "firehose-opensearch" {
  statement {
    effect  = "Allow"
    actions = ["es:*"]

    resources = [
      aws_opensearch_domain.test_cluster.arn,
      "${aws_opensearch_domain.test_cluster.arn}/*",
    ]
  }
}

resource "aws_iam_role_policy" "firehose-opensearch" {
  name   = "opensearch"
  role   = aws_iam_role.firehose_role.id
  policy = data.aws_iam_policy_document.firehose-opensearch.json
}

data "aws_iam_policy_document" "main" {
  statement {
    effect = "Allow"

    principals {
      type        = "*"
      identifiers = ["*"]
    }

    condition {
      test     = "IpAddress"
      variable = "aws:SourceIp"
      values   = ["127.0.0.1/32"]
    }

    actions   = ["es:*"]
    resources = ["${aws_opensearch_domain.test_cluster.arn}/*"]
  }
}

# applied at service level, necessary for opensearch access
resource "aws_opensearch_domain_policy" "main" {
  domain_name     = aws_opensearch_domain.test_cluster.domain_name
  access_policies = data.aws_iam_policy_document.main.json
}

resource "aws_kinesis_firehose_delivery_stream" "test" {
  depends_on = [aws_iam_role_policy.firehose-opensearch]

  name        = "terraform-kinesis-firehose-os"
  destination = "opensearch"

  opensearch_configuration {
    domain_arn = aws_opensearch_domain.test_cluster.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "test"

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.januaryseventh.arn
      buffering_size     = 10
      buffering_interval = 400
      compression_format = "GZIP"
    }
  }
}

response:
```hcl
resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_kinesis_firehose_delivery_stream" "opensearch_destination" {
  name        = "opensearch-delivery-${random_id.suffix.hex}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_opensearch.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose-data/"

    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }

    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/${aws_kinesis_firehose_delivery_stream.opensearch_destination.name}"
      log_stream_name = "S3Delivery"
    }
  }

  s3_backup_configuration {
    role_arn   = aws_iam_role.firehose_backup.arn
    bucket_arn = aws_s3_bucket.firehose_backup_bucket.arn
    prefix     = "firehose-backup/"
  }

  tags = {
    Name = "OpenSearchDeliveryStream"
  }
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-data-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_bucket" "firehose_backup_bucket" {
  bucket = "firehose-backup-bucket-${random_id.suffix.hex}"
}

resource "aws_iam_role" "firehose_opensearch" {
  name = "firehose-opensearch-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role" "firehose_backup" {
  name = "firehose-backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_opensearch_policy" {
  name = "firehose-opensearch-policy"
  role = aws_iam_role.firehose_opensearch.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.firehose_bucket.arn,
          "${aws_s3_bucket.firehose_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents",
          "logs:CreateLogGroup",
          "logs:CreateLogStream"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "opensearch:CreateIndex",
          "opensearch:PutItem",
          "opensearch:UpdateItem",
          "opensearch:GetItem",
          "opensearch:DeleteItem"
        ],
        Resource = "arn:aws:opensearch:${var.aws_region}:${data.aws_caller_identity.current.account_id}:domain/*"
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_backup_policy" {
  name = "firehose-backup-policy"
  role = aws_iam_role.firehose_backup.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetBucketLocation"
        ]
        Resource = [
          aws_s3_bucket.firehose_backup_bucket.arn,
          "${aws_s3_bucket.firehose_backup_bucket.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_opensearch_domain" "example" {
  domain_name    = "opensearch-domain-${random_id.suffix.hex}"
  engine_version = "OpenSearch_1.3"

  cluster_config {
    instance_type = "t3.small.search"
    instance_count = 1
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  access_policies = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.firehose_opensearch.arn
        }
        Action = [
          "es:*"
        ]
        Resource = "arn:aws:es:${var.aws_region}:${data.aws_caller_identity.current.account_id}:domain/${aws_opensearch_domain.example.domain_name}/*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}
```

