resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_kinesisfirehose_delivery_stream" "opensearch_destination" {
  name        = "opensearch-delivery-${random_id.suffix.hex}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_opensearch.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    prefix     = "firehose-opensearch-raw/"
    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_logs.name
      log_stream_name = "opensearch-delivery-stream"
    }
    error_output_prefix = "firehose-opensearch-error/"
  }

  # OpenSearch destination configuration
  opensearch_destination_configuration {
    role_arn   = aws_iam_role.firehose_opensearch.arn
    s3_backup_mode = "FailedDocumentsOnly"
    s3_configuration {
      role_arn   = aws_iam_role.firehose_s3_backup.arn
      bucket_arn = aws_s3_bucket.firehose_backup_bucket.arn
      prefix     = "firehose-opensearch-backup/"
    }
    opensearch_collection_name = "firehose-data"
    opensearch_endpoint        = aws_opensearch_domain.example.endpoint
    opensearch_region          = "us-east-1"
    opensearch_index_rotation {
      enabled = true
      interval = "OneHour"
      size     = "5GB"
    }
    opensearch_http_config {
      enabled = true
      vpc_config {
        security_group_ids = [aws_security_group.firehose_opensearch.id]
        subnet_ids         = aws_subnet.firehose_subnet[*].id
      }
    }
    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = aws_cloudwatch_log_group.firehose_logs.name
      log_stream_name = "opensearch-destination-stream"
    }
    processing_configuration {
      enabled = true
      processors {
        type = "Lambda"
        parameters = [
          {
            parameter_name  = "LambdaArn"
            parameter_value = aws_lambda_function.firehose_processor.arn
          }
        ]
      }
    }
  }

  tags = {
    Name = "OpenSearch-Delivery-Stream"
  }
}

# Supporting resources
resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-opensearch-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_bucket" "firehose_backup_bucket" {
  bucket = "firehose-opensearch-backup-bucket-${random_id.suffix.hex}"
}

resource "aws_cloudwatch_log_group" "firehose_logs" {
  name = "/aws/kinesisfirehose/firehose-opensearch-logs"
}

resource "aws_opensearch_domain" "example" {
  domain_name    = "firehose-opensearch-domain"
  engine_version = "OpenSearch_1.3"

  cluster_config {
    instance_type     = "t3.small.search"
    instance_count    = 1
    zone_awareness_enabled = false
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  vpc_options {
    security_group_ids = [aws_security_group.opensearch.id]
    subnet_ids         = aws_subnet.opensearch_subnet[*].id
  }

  encrypt_at_rest {
    enabled = true
  }

  node_to_node_encryption {
    enabled = true
  }

  tags = {
    Environment = "Development"
  }
}

resource "aws_security_group" "firehose_opensearch" {
  name        = "firehose-opensearch-sg"
  description = "Allow traffic from Firehose to OpenSearch"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    security_groups = [aws_security_group.opensearch.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "opensearch" {
  name        = "opensearch-sg"
  description = "Allow traffic to OpenSearch"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "firehose_subnet" {
  count             = 2
  vpc_id            = aws_vpc.example.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = "us-east-1${count.index + 1}"
}

resource "aws_subnet" "opensearch_subnet" {
