    cloudwatch_logging_options {
      enabled         = true
      log_group_name  = "/aws/kinesisfirehose/firehose-s3-destination-${random_id.suffix.hex}"
      log_stream_name = "S3ExtendedDelivery"
    }
    prefixer = "firehose-data/" # Optional: Prefix for files in S3
    error_output_prefix = "firehose-errors/" # Optional: Prefix for error files
  }
}

