  zone_id = aws_route53_zone.primary.zone_id
  name    = "primary.example.com" # Replace with your desired subdomain
  type    = "A"

  alias {
    name                   = aws_route53_health_check.primary_health_check.health_check_config.fully_qualified_health_check_domain
    zone_id                = aws_route53_health_check.primary_health_check.health_check_config.fully_qualified_health_check_domain == "example.com" ? "Z3AQBSTGFYJSTF" : "Z2FDTNDATAQYW2" # Default AWS health check zone IDs
    evaluate_target_health = true
    failover_routing_policy {
      type = "ACTIVE"
    }
  }

  set_identifier = "primary"
}

resource "aws_route53_record" "secondary_failover" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "primary.example.com" # Same subdomain as primary
  type    = "A"

  alias {
    name                   = "backup.example.com" # Replace with your backup endpoint
    zone_id                = "Z3AQBSTGFYJSTF" # Default AWS zone ID for Route 53 hosted zones
    evaluate_target_health = true
    failover_routing_policy {
      type = "PRIMARY"
    }
  }

  set_identifier = "secondary"
}

