resource "random_id" "policy_suffix" {
  byte_length = 4
}

resource "aws_route53_policy" "traffic_management" {
  name = "traffic-management-policy-${random_id.policy_suffix.hex}"
  type = "TRAFFIC_MANAGEMENT"
  description = "Traffic management policy for load balancing across regions"

  policy {
    name = "weighted-region-routing"
    type = "WEIGHTED"

    weighted_routing_policy {
      weighted_record_set {
        record_name = "example.com"
        record_type = "A"

        alias {
          name = "example-alias"
          evaluate_target_health = false
          zone_id = "Z35SXDOTRQ7X7K" # Default AWS global alias zone ID
        }

        weighted_record {
          weight = 50
          region = "us-east-1"
          health_check_id = aws_route53_health_check.example.id
        }

        weighted_record {
          weight = 30
