provider "aws" {
  region = "us-east-1" # Change to your preferred region
}

resource "aws_caller_identity" "current" {}

data "aws_ecr_repository" "eks" {
  name = "eks-stable" # Replace with your ECR repository name
}

data "aws_ecr_repository" "stable_image" {
  name = data.aws_ecr_repository.eks.name
}

data "aws_ecr_image" "stable" {
  repository_name = data.aws_ecr_repository.eks.name
  image_tag       = "stable"
}

locals {
  image_tag = data.aws_ecr_image.stable.image_tag
  aws_tags = {
    Terraform   = "true"
    Environment = terraform.workspace
  }
  workspace_name = terraform.workspace
}

module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 19.0"

  cluster_name    = "eks-cluster-${local.workspace_name}"
  cluster_version = "1.28"
  subnets         = ["subnet-12345678", "subnet-87654321"] # Replace with your subnet IDs
  vpc_id          = "vpc-12345678" # Replace with your VPC ID

  node_groups = [
    {
      name          = "worker-group"
      instance_type = "t3.medium"
      desired_size  = 2
      min_size      = 1
      max_size      = 3
      iam_role_arn  = aws_iam_role.node_group.arn
    }
  ]

  node_groups_iam_role_additional_policies = [
    "arn:aws:iam::aws:policy/AmazonEC2ContainerRegistryReadOnly"
  ]

  tags = local.aws_tags
}

data "aws_eks_cluster" "cluster" {
  name = module.eks.cluster_id
}

data "aws_eks_cluster_auth" "cluster" {
  name = module.eks.cluster_id
}

provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority.0.data)
  token                  = data.aws_eks_cluster_auth.cluster.token
}

provider "helm" {
  kubernetes {
    host                   = data.aws_eks_cluster.cluster.endpoint
    cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority.0.data)
    token                  = data.aws_eks_cluster_auth.cluster.token
  }
}

resource "aws_iam_role" "node_group" {
  name = "eks-node-group-role-${local.workspace_name}"

