variable "cluster_name" {
  description = "The name of the EKS cluster to which the add-on will be attached"
  type        = string
}

resource "aws_eks_addon" "vpc_cni" {
  cluster_name             = var.cluster_name
  addon_name               = "vpc-cni"
  addon_version            = "v1.14.2" # Specify the desired version
  resolve_conflicts        = "OVERWRITE"
  most_recent              = false
  service_account_role_arn = aws_iam_role.vpc_cni.arn # Requires IAM role setup (see below)
}

# IAM Role for VPC CNI Add-on (required)
resource "aws_iam_role" "vpc_cni" {
  name = "${var.cluster_name}-vpc-cni-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "vpc_cni_amazon_eks_worker_node_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSWorkerNodePolicy"
