    Id      = "DenyAccessFromBlockedIP"
    Statement = [
      {
        Sid       = "DenyAccessFromBlockedIP"
        Effect    = "Deny"
        Principal = "*"
        Action    = "s3:*"
        Resource  = [
          "arn:aws:s3:::my_bucket",
          "arn:aws:s3:::my_bucket/*"
        ]
        Condition = {
          IpAddress = {
            "aws:SourceIp" = var.blocked_ip
          }
        }
      }
    ]
  })
}

