  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
  tags = {
    Name = "main-igw"
  }
}

resource "aws_subnet" "private_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "private-subnet-a"
  }
}

resource "aws_subnet" "private_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-subnet-b"
  }
}

resource "aws_eip" "nat" {
  vpc = true
  tags = {
    Name = "nat-eip"
  }
}

resource "aws_nat_gateway" "nat" {
  allocation_id = aws_eip.nat.id
  subnet_id     = aws_subnet.private_a.id
  tags = {
    Name = "nat-gateway"
  }
}

resource "aws_route_table" "private" {
  vpc_id = aws_vpc.main.id
  route {
    cidr_block     = "0.0.0.0/0"
    nat_gateway_id = aws_nat_gateway.nat.id
  }
  tags = {
    Name = "private-route-table"
  }
}

resource "aws_route_table_association" "private_a" {
  subnet_id      = aws_subnet.private_a.id
  route_table_id = aws_route_table.private.id
}

resource "aws_route_table_association" "private_b" {
  subnet_id      = aws_subnet.private_b.id
  route_table_id = aws_route_table.private.id
}

resource "aws_security_group" "private_sg" {
  name        = "private-sg"
  description = "Allow SSH and NFS traffic"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  ingress {
    from_port   = 2049
    to_port     = 2049
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_efs_file_system" "shared_efs" {
  creation_token = "shared-efs-${random_id.suffix.hex}"
  encrypted      = true
  tags = {
    Name = "shared-efs"
  }
}

resource "aws_efs_mount_target" "private_a" {
  file_system_id  = aws_efs_file_system.shared_efs.id
  subnet_id       = aws_subnet.private_a.id
  security_groups = [aws_security_group.private_sg.id]
}

resource "aws_efs_mount_target" "private_b" {
  file_system_id  = aws_efs_file_system.shared_efs.id
  subnet_id       = aws_subnet.private_b.id
  security_groups = [aws_security_group.private_sg.id]
}

resource "aws_instance" "ec2_instance_a" {
  ami                    = "ami-0c55b159cbfafe1f0" # Latest Amazon Linux 2 AMI (us-east-1)
  instance_type          = "t3.medium"
  subnet_id              = aws_subnet.private_a.id
  vpc_security_group_ids = [aws_security_group.private_sg.id]
  associate_public_ip_address = false
  key_name               = "your-key-pair" # Replace with your key pair name
  user_data              = <<-EOF
                              #!/bin/bash
                              sudo yum update -y
                              sudo yum install -y amazon-efs-utils
                              sudo mkdir -p /mnt/shared_efs
                              sudo mount -t nfs4 -o nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport ${aws_efs_file_system.shared_efs.dns_name}:/ /mnt/shared_efs
                              echo "${aws_efs_file_system.shared_efs.dns_name}:/ /mnt/shared_efs nfs4 nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport 0 0" | sudo tee -a /etc/fstab
                              EOF
  tags = {
    Name = "ec2-instance-a"
  }
}

resource "aws_instance" "ec2_instance_b" {
  ami                    = "ami-0c55b159cbfafe1f0" # Latest Amazon Linux 2 AMI (us-east-1)
  instance_type          = "t3.medium"
  subnet_id              = aws_subnet.private_b.id
  vpc_security_group_ids = [aws_security_group.private_sg.id]
  associate_public_ip_address = false
  key_name               = "your-key-pair" # Replace with your key pair name
  user_data              = <<-EOF
                              #!/bin/bash
                              sudo yum update -y
                              sudo yum install -y amazon-efs-utils
                              sudo mkdir -p /mnt/shared_efs
                              sudo mount -t nfs4 -o nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport ${aws_efs_file_system.shared_efs.dns_name}:/ /mnt/shared_efs
                              echo "${aws_efs_file_system.shared_efs.dns_name}:/ /mnt/shared_efs nfs4 nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport 0 0" | sudo tee -a /etc/fstab
                              EOF
  tags = {
    Name = "ec2-instance-b"
  }
}
