  cluster_type       = "multi-node"
  number_of_nodes    = 2
  publicly_accessible = true
  skip_final_snapshot = true

  encrypted = true
  iam_roles = ["arn:aws:iam::123456789012:role/redshift-service-role"]

  tags = {
    Name = "RedshiftCluster"
  }
}

resource "random_password" "redshift" {
  length  = 20
  special = false
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg-${random_id.suffix.hex}"
  description = "Allow access to Redshift cluster"
  vpc_id      = "vpc-12345678" # Replace with your VPC ID

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust based on your security requirements
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_redshift_cluster_security_group" "cluster_sg" {
  cluster_identifier = aws_redshift_cluster.main.id
  sg_rules           = [
    {
      rule_type = "ingress",
      rule     = {
        from_port   = 5439
        to_port     = 5439
        protocol    = "tcp"
        ec2        = {
          security_group_id = aws_security_group.redshift_sg.id
        }
      }
    }
  ]
}
