  filename      = data.archive_file.lambda_zip_file.output_path
  function_name = "lambda_app_function"
  source_code_hash = data.archive_file.lambda_zip_file.output_base64sha256
  role          = aws_iam_role.iam_for_lambda.arn
  handler       = "app.handler"
  runtime       = "nodejs18.x"
}

