  })
}

resource "aws_iam_policy" "lambda_basic" {
  name        = "lambda_basic_execution"
  description = "Basic execution policy for Lambda"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_logs" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = aws_iam_policy.lambda_basic.arn
}

resource "aws_lambda_function" "lambda_js" {
  filename      = "lambda.js"
  function_name = "lambda_js_function"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler" # Adjust handler if your file exports a different function
  runtime       = "nodejs18.x"    # Adjust runtime if your lambda.js uses a different runtime

  source_code_hash = filebase64sha256("lambda.js") # Ensure lambda.js is in the same directory as the .tf file
}
```

