      "ParameterDefinitions" : [
        {
          "Name" : "InputDataConfig",
          "Type" : "String"
        },
        {
          "Name" : "ModelApprovalStatus",
          "Type" : "String"
        }
      ],
      "Parameters" : {
        "InputDataConfig" : {
          "DefaultValue" : "s3://my-bucket/input-data/"
        },
        "ModelApprovalStatus" : {
          "DefaultValue" : "PendingManualApproval"
        }
      },
      "Steps" : [
        {
          "Name" : "DownloadInputData",
          "Properties" : {
            "Input" : [
              {
                "Source" : "InputDataConfig"
              }
            ],
            "ProcessorEndpointConfig" : {
              "EndpointConfigName" : "data-processing-endpoint"
            },
            "Output" : [
              {
                "OutputName" : "ProcessedData",
                "Source" : "/opt/ml/processing/output"
              }
            ]
          },
          "Type" : "Processing"
        },
        {
          "Name" : "TrainModel",
          "Properties" : {
            "Input" : [
              {
                "Source" : "ProcessedData"
              }
            ],
            "AlgorithmSpecification" : {
              "TrainingImage" : "763104351884.dkr.ecr.us-west-2.amazonaws.com/huggingface-pytorch-training:1.8.1-gpu-py38-cu110-ubuntu20.04",
              "TrainingInputMode" : "File"
            },
            "OutputDataConfig" : {
              "S3OutputPath" : "s3://my-bucket/output/"
            },
            "ResourceConfig" : {
              "InstanceType" : "ml.p3.2xlarge",
              "InstanceCount" : 1,
              "VolumeSizeInGB" : 30
            },
            "RoleArn" : "arn:aws:iam::123456789012:role/service-role/AmazonSageMaker-ExecutionRole"
          },
          "Type" : "Training"
        },
        {
          "Name" : "CreateModel",
          "Properties" : {
            "ModelPackageGroupName" : "ExampleModelPackageGroup",
            "ModelName" : "ExampleModel",
            "ApprovalStatus" : {
              "Ref" : "ModelApprovalStatus"
            }
          },
          "Type" : "CreateModel"
        }
      ]
    }
  })

  tags = {
    Name = "sagemaker-pipeline-example"
  }
}

resource "aws_sagemaker_processing_endpoint" "data_processing" {
  name = "data-processing-endpoint"
  processing_endpoint_config_name = aws_sagemaker_processing_endpoint_config.example.name
}

resource "aws_sagemaker_processing_endpoint_config" "example" {
  name = "data-processing-endpoint-config"
  processing_endpoint_config {
    processing_endpoint_config_name = "data-processing-endpoint-config"
    processing_role_arn = "arn:aws:iam::123456789012:role/service-role/AmazonSageMaker-ExecutionRole"
    processing_config {
      processing_config_name = "data-processing-config"
      processing_app_specification {
        image_uri = "763104351884.dkr.ecr.us-west-2.amazonaws.com/huggingface-pytorch-processing:1.8.1-gpu-py38-cu110-ubuntu20.04"
        environment {
          key   = "SAGEMAKER_PROGRAM"
          value = "process.py"
        }
      }
      processing_resource_specification {
        instance_type = "ml.m5.xlarge"
        instance_count = 1
      }
    }
  }
}
