        Resource = "*"
      }
    ]
  })
}

resource "aws_kafka_topic" "logs_topic" {
  kafka_cluster_id = aws_kafka_cluster.example.id
  topic_name       = "kafka-logs-topic-${random_id.cluster_suffix.hex}"
  partitions       = 3
  replication_factor = 2
}

resource "aws_kafka_topic_configuration" "logs_topic_config" {
  kafka_cluster_id = aws_kafka_cluster.example.id
  topic_name       = aws_kafka_topic.logs_topic.topic_name
  configurations = jsonencode([
    {
      name  = "log.retention.ms",
      value = "604800000"
    },
    {
      name  = "log.segment.bytes",
      value = "1073741824"
    }
  ])
}

resource "aws_kinesis_firehose_consumer" "kafka_consumer" {
  delivery_stream_arn = aws_kinesis_firehose_delivery_stream.kafka_logs.arn
  kafka_consumer {
    bootstrap_servers = aws_kafka_cluster.example.bootstrap_brokers_sasl_iam
    topic_name        = aws_kafka_topic.logs_topic.topic_name
    consumer_group_id = "firehose-consumer-group-${random_id.cluster_suffix.hex}"
  }
}
