resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_kms_key" "msk_key" {
  description             = "KMS key for MSK cluster encryption"
  deletion_window_in_days = 30
  enable_key_rotation     = true
}

resource "aws_s3_bucket" "msk_logs" {
  bucket = "msk-logs-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_server_side_encryption_configuration" "msk_logs" {
  bucket = aws_s3_bucket.msk_logs.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/kafka/msk-cluster-logs-${random_id.suffix.hex}"
  retention_in_days = 7
}

resource "aws_kinesis_firehose_delivery_stream" "msk_logs" {
  name        = "msk-logs-delivery-${random_id.suffix.hex}"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_s3.arn
    bucket_arn = aws_s3_bucket.msk_logs.arn
    prefix     = "msk-logs/"
    error_output_prefix = "msk-logs-error/"
    buffering_hints {
      size_in_mb   = 5
      interval_in_seconds = 300
    }
  }
}

resource "aws_iam_role" "firehose_s3" {
  name = "firehose-s3-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_s3" {
  name = "firehose-s3-policy-${random_id.suffix.hex}"
  role = aws_iam_role.firehose_s3.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:PutObject"
        ],
        Resource = [
          aws_s3_bucket.msk_logs.arn,
          "${aws_s3_bucket.msk_logs.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "kms:GenerateDataKey*",
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GrantPermissions",
          "kms:CreateGrant"
        ],
        Resource = [aws_kms_key.msk_key.arn]
      }
    ]
  })
}

resource "aws_kafka_cluster" "msk" {
  cluster_name           = "msk-cluster-${random_id.suffix.hex}"
  kafka_version          = "3.4.0"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.t3.small"
    client_subnets  = ["subnet-12345678", "subnet-87654321"] # Replace with your actual subnets
    security_groups = [aws_security_group.msk.id]
  }

  encryption_info {
    encryption_in_transit {
      client_broker = "TLS_PLAINTEXT"
    }
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_key.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {
        enabled_in_broker = true
      }
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }
      s3 {
        enabled = true
        bucket = aws_s3_bucket.msk_logs.bucket
      }
      firehose {
        enabled = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs.name
      }
    }
  }

  tags = {
    Name = "msk-cluster-${random_id.suffix.hex}"
  }
}

resource "aws_security_group" "msk" {
  name        = "msk-cluster-sg-${random_id.suffix.hex}"
  description = "Security group for MSK cluster"

  ingress {
    from_port   = 9098
    to_port     = 9098
    protocol    = "TCP"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}
