          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ]
        Resource = [
          aws_cloudwatch_log_group.msk.arn,
          "${aws_cloudwatch_log_group.msk.arn}:*"
        ]
      }
    ]
  })
}

# Upload debezium plugin to S3
resource "aws_s3_object" "debezium_plugin" {
  bucket = aws_s3_bucket.msclogs.bucket
  key    = "plugins/debezium.zip"
  source = "path/to/debezium.zip" # Replace with actual path to debezium.zip
  etag   = filemd5("path/to/debezium.zip") # Replace with actual path to debezium.zip
}

# MSK Connect Custom Plugin
resource "aws_mskconnect_custom_plugin" "debezium_plugin" {
  name            = "debezium-plugin-${random_id.suffix.hex}"
  content_location {
    s3 {
      bucket_arn = aws_s3_bucket.msclogs.arn
      file_key   = aws_s3_object.debezium_plugin.key
      version    = aws_s3_object.debezium_plugin.version_id
    }
  }
}

# MSK Connect Connector
resource "aws_mskconnect_connector" "debezium_connector" {
  name           = "debezium-connector-${random_id.suffix.hex}"
  kafka_cluster {
    kafka_cluster_arn = aws_msk_cluster.mscluster.arn
    vpc {
      security_groups = [aws_security_group.msk_sg.id]
      subnets         = ["subnet-12345678", "subnet-87654321", "subnet-fedcba09"]
    }
  }
  kafka_cluster_client_authentication {
    authentication_type = "IAM"
  }
  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS_PLAINTEXT"
  }
  kafka_cluster_client_authentication {
    authentication_type = "IAM"
  }
  kafka_cluster_encryption_in_transit {
    encryption_type = "TLS_PLAINTEXT"
  }
  custom_plugin {
    id          = aws_mskconnect_custom_plugin.debezium_plugin.id
    configuration = jsonencode({
      "connector.class" = "io.debezium.connector.mysql.MySqlConnector",
      "tasks.max"       = "1",
      "database.hostname" = "your-database-host",
      "database.port"   = "3306",
      "database.user"   = "db_user",
      "database.password" = "db_password",
      "database.server.id" = "1",
      "database.server.name" = "mysql-server",
      "database.include.list" = "your_database",
      "transforms" = "unwrap",
      "transforms.unwrap.type" = "io.debezium.transforms.ExtractNewRecordState"
    })
  }
  log_delivery {
    cloudwatch_logs {
      log_group = aws_cloudwatch_log_group.msk.name
      log_stream = "msk-connect-log-stream"
    }
  }
  service_execution_role_arn = aws_iam_role.msk_connect_role.arn
}

resource "aws_iam_role" "msk_connect_role" {
  name = "msk-connect-role-${random_id.suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "mskconnect.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "msk_connect_policy" {
  name = "msk-connect-policy-${random_id.suffix.hex}"
  role = aws_iam_role.msk_connect_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ],
        Resource = [
          aws_cloudwatch_log_group.msk.arn,
          "${aws_cloudwatch_log_group.msk.arn}:*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ],
        Resource = [
          "${aws_s3_bucket.msclogs.arn}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "kms:Decrypt"
        ],
        Resource = [
          aws_kms_key.mskey.arn
        ]
      }
    ]
  })
}
```

