  db_cluster_identifier = aws_db_cluster.mysql_cluster.id
  instance_class     = "db.r5.large"
  db_subnet_group_name = aws_db_subnet_group.mysql_subnet_group.name
  availability_zone   = "us-east-1b"
  storage_type       = "gp2"
  storage_encrypted   = true
}

resource "aws_db_instance" "cluster_instance_1c" {
  identifier         = "aurora-mysql-instance-1c-${random_id.suffix.hex}"
  engine             = aws_db_cluster.mysql_cluster.engine
  engine_version     = aws_db_cluster.mysql_cluster.engine_version
  db_cluster_identifier = aws_db_cluster.mysql_cluster.id
  instance_class     = "db.r5.large"
  db_subnet_group_name = aws_db_subnet_group.mysql_subnet_group.name
  availability_zone   = "us-east-1c"
  storage_type       = "gp2"
  storage_encrypted   = true
}

resource "aws_db_subnet_group" "mysql_subnet_group" {
  name       = "aurora-mysql-subnet-group-${random_id.suffix.hex}"
  subnet_ids = [
    aws_subnet.subnet_1a.id,
    aws_subnet.subnet_1b.id,
    aws_subnet.subnet_1c.id
  ]
}

resource "aws_vpc" "mysql_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet_1a" {
  vpc_id     = aws_vpc.mysql_vpc.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet_1b" {
  vpc_id     = aws_vpc.mysql_vpc.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_subnet" "subnet_1c" {
  vpc_id     = aws_vpc.mysql_vpc.id
  cidr_block = "10.0.3.0/24"
  availability_zone = "us-east-1c"
}

resource "aws_db_cluster_parameter_group" "mysql_cluster_param_group" {
  name        = "aurora-mysql-cluster-param-group-${random_id.suffix.hex}"
  family      = "aurora-mysql5.7"

  parameter {
    name  = "character_set_server"
    value = "utf8mb4"
  }

  parameter {
    name  = "collation_server"
    value = "utf8mb4_unicode_ci"
  }
}

resource "aws_db_cluster" "mysql_cluster" {
  engine_mode               = "multi-az"
  engine                    = "aurora-mysql"
  database_name             = "auroramysqlcluster"
  master_username           = "admin"
  master_password           = random_password.db.result
  storage_encrypted         = true
  backup_retention_period   = 7
  preferred_backup_window   = "07:00-09:00"
  skip_final_snapshot       = true
  enable_http_endpoint      = true
  parameter_group_name      = aws_db_cluster_parameter_group.mysql_cluster_param_group.name
  storage_encryption_kms_key_id = aws_kms_key.mysql_kms_key.arn
}

resource "aws_kms_key" "mysql_kms_key" {
  description = "KMS key for MySQL Aurora Cluster encryption"
  policy      = data.aws_iam_policy_document.kms_policy.json
}

data "aws_iam_policy_document" "kms_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions = ["kms:*"]
    resources = ["*"]
  }
}

data "aws_caller_identity" "current" {}
```

