resource "aws_kms_key" "chime_kms_key" {
  description = "KMS key for Chime Media Metrics Logs"
  policy = data.aws_iam_policy_document.chime_kms_key_policy.json
}

data "aws_iam_policy_document" "chime_kms_key_policy" {
  statement {
    sid    = "Enable IAM User Permissions"
    effect = "Allow"
    principals {
      type        = "AWS"
      identifiers = ["arn:aws:iam::${data.aws_caller_identity.current.account_id}:root"]
    }
    actions = ["kms:*"]
    resources = ["*"]
  }

  statement {
    sid    = "Allow Chime Voice Connector to encrypt logs"
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["chime.amazonaws.com"]
    }
    actions = [
      "kms:GenerateDataKey*",
      "kms:Encrypt*",
      "kms:ReEncrypt*",
      "kms:DescribeKey"
    ]
    resources = ["*"]
  }
}

resource "aws_iam_policy" "chime_media_logs_policy" {
  name        = "chime-media-logs-policy-${random_id.suffix.hex}"
  description = "Policy for Chime Media Metrics Logs"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.chime_logs.arn,
          "${aws_s3_bucket.chime_logs.arn}/*"
        ]
      }
    ]
  })
}

