}

resource "aws_codebuild_source_credential" "github" {
  server_type = "GITHUB"
  token       = var.github_token
}

resource "aws_codebuild_project" "autograding" {
  name          = "autograding-${random_id.suffix.hex}"
  description   = "Autograding system for computer science course"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_LARGE"
    image           = "aws/codebuild/standard:5.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "GITHUB_REPO"
      value = var.github_repo
    }

    environment_variable {
      name  = "GITHUB_BRANCH"
      value = var.github_branch
    }

    environment_variable {
      name  = "GRADE_SCRIPT"
      value = "autograder.sh"
    }
  }

  source {
    type      = "GITHUB"
    location  = var.github_repo
    git_clone_depth = 1
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install pytest pytest-cov
        pre_build:
          commands:
            - echo "Checking out repository..."
            - git clone https://${GITHUB_REPO} . --branch ${GITHUB_BRANCH} --depth 1
        build:
          commands:
            - echo "Running autograder..."
            - chmod +x ${GRADE_SCRIPT}
            - ./${GRADE_SCRIPT}
      artifacts:
        files: '**/*'
      cache:
        paths: '/root/.cache/pip/**/*'
    EOT
  }

  tags = {
    Name = "Autograding-${random_id.suffix.hex}"
  }
}

resource "aws_s3_bucket" "autograding_artifacts" {
  bucket = "autograding-artifacts-${data.aws_region.current.name}-${data.aws_caller_identity.current.account_id}"
}

resource "aws_s3_bucket_versioning" "autograding_artifacts" {
  bucket = aws_s3_bucket.autograding_artifacts.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_cloudwatch_log_group" "autograding" {
  name              = "/aws/codebuild/autograding-${random_id.suffix.hex}"
  retention_in_days = 7
}

