# Variables for autograding system configuration
variable "github_repo_owner" {
  description = "Owner of the GitHub repository"
  type        = string
}

variable "github_repo_name" {
  description = "Name of the GitHub repository"
  type        = string
}

variable "github_branch" {
  description = "GitHub branch to monitor for submissions"
  type        = string
  default     = "main"
}

variable "github_token" {
  description = "GitHub personal access token for webhook"
  type        = string
  sensitive   = true
}

variable "s3_bucket_name" {
  description = "Name of the S3 bucket for storing submissions and results"
  type        = string
}

variable "codebuild_project_name" {
  description = "Name of the CodeBuild project for execution"
  type        = string
}

variable "environment_name" {
  description = "Name of the predefined execution environment"
  type        = string
}

# IAM Role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "${var.codebuild_project_name}-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_service" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
}

resource "aws_iam_role_policy" "s3_access" {
  name = "${var.codebuild_project_name}-s3-access"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Resource = [
          "arn:aws:s3:::${var.s3_bucket_name}",
          "arn:aws:s3:::${var.s3_bucket_name}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      }
    ]
  })
}

# S3 Bucket for storing submissions and results
resource "aws_s3_bucket" "autograding" {
  bucket = var.s3_bucket_name
}

resource "aws_s3_bucket_versioning" "autograding" {
  bucket = aws_s3_bucket.autograding.id
  versioning_configuration {
    status = "Enabled"
  }
}

# CodeBuild Project for execution
resource "aws_codebuild_project" "autograding" {
  name          = var.codebuild_project_name
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    environment_variable {
      name  = "S3_BUCKET"
      value = var.s3_bucket_name
    }
    environment_variable {
      name  = "GITHUB_REPO"
      value = "${var.github_repo_owner}/${var.github_repo_name}"
    }
    environment_variable {
      name  = "GITHUB_BRANCH"
      value = var.github_branch
    }
    environment_variable {
      name  = "ENVIRONMENT_NAME"
      value = var.environment_name
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/${var.github_repo_owner}/${var.github_repo_name}"
    git_clone_depth = 1
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install pytest
        pre_build:
          commands:
            - echo "Downloading submission from S3..."
            - aws s3 cp s3://${var.s3_bucket_name}/submissions/${CODEBUILD_RESOLVED_SOURCE_VERSION}.zip .
            - unzip ${CODEBUILD_RESOLVED_SOURCE_VERSION}.zip
        build:
          commands:
            - echo "Running tests..."
            - python -m pytest --junitxml=test-results.xml .
        post_build:
          commands:
            - echo "Uploading results to S3..."
            - aws s3 cp test-results.xml s3://${var.s3_bucket_name}/results/${CODEBUILD_RESOLVED_SOURCE_VERSION}/test-results.xml
            - aws s3 cp -r output/ s3://${var.s3_bucket_name}/results/${CODEBUILD_RESOLVED_SOURCE_VERSION}/output/
      artifacts:
        files: '**/*'
      cache:
        paths: '/root/.cache/pip/**/*'
    EOT
  }
}

# Lambda Function for triggering CodeBuild
resource "aws_iam_role" "lambda_role" {
  name = "${var.codebuild_project_name}-lambda-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lambda_s3_access" {
  name = "${var.codebuild_project_name}-lambda-s3-access"
  role = aws_iam_role.lambda_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Resource = [
          "arn:aws:s3:::${var.s3_bucket_name}",
          "arn:aws:s3:::${var.s3_bucket_name}/*"
        ]
      },
      {
        Effect = "Allow",
        Action = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ],
        Resource = "*"
      },
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "*"
      }
    ]
  })
}

resource "aws_lambda_function" "trigger_codebuild" {
  function_name = "${var.codebuild_project_name}-trigger"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.lambda_handler"
  runtime       = "python3.8"
  filename      = "data/lambda_trigger.zip"

  environment {
    variables = {
      CODEBUILD_PROJECT = var.codebuild_project_name
      S3_BUCKET         = var.s3_bucket_name
    }
  }
}

# API Gateway for receiving GitHub webhook
resource "aws_api_gateway_rest_api" "github_webhook" {
  name = "${var.codebuild_project_name}-webhook"
}

resource "aws_api_gateway_resource" "webhook" {
  rest_api_id = aws_api_gateway_rest_api.github_webhook.id
  parent_id   = aws_api_gateway_rest_api.github_webhook.root_resource_id
  path_part   = "webhook"
}

resource "aws_api_gateway_method" "webhook_post" {
  rest_api_id   = aws_api_gateway_rest_api.github_webhook.id
  resource_id   = aws_api_gateway_resource.webhook.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "webhook_lambda" {
  rest_api_id = aws_api_gateway_rest_api.github_webhook.id
  resource_id = aws_api_gateway_resource.webhook.id
  http_method = aws_api_gateway_method.webhook_post.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.trigger_codebuild.invoke_arn
}

resource "aws_lambda_permission" "apigw_lambda" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.trigger_codebuild.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.github_webhook.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "webhook_deployment" {
  depends_on = [aws_api_gateway_integration.webhook_lambda]
  rest_api_id = aws_api_gateway_rest_api.github_webhook.id
  stage_name  = "prod"
}

# CloudWatch Event Rule for triggering Lambda on GitHub push
resource "aws_cloudwatch_event_rule" "github_push" {
  name                = "${var.codebuild_project_name}-github-push"
  description         = "Trigger on GitHub push events"
  schedule_expression = "rate(1 hour)" # Adjust as needed
}

resource "aws_cloudwatch_event_target" "lambda_trigger" {
  rule      = aws_cloudwatch_event_rule.github_push.name
  target_id = "TriggerLambda"
  arn       = aws_lambda_function.trigger_codebuild.arn
}

# Lambda Layer for GitHub Webhook Handling
resource "aws_lambda_layer_version" "github_webhook_layer" {
  layer_name          = "${var.codebuild_project_name}-github-webhook-layer"
  compatible_runtimes = ["python3.8"]
  filename            = "data/github_webhook_layer.zip"
  source_code_hash    = filebase64sha256("data/github_webhook_layer.zip")
}

resource "aws_lambda_function" "github_webhook_handler" {
  function_name = "${var.codebuild_project_name}-github-webhook-handler"
  role          = aws_iam_role.lambda_role.arn
  handler       = "github_webhook.handler"
  runtime       = "python3.8"
  layers        = [aws_lambda_layer_version.github_webhook_layer.arn]
  filename      = "data/github_webhook_handler.zip"
  environment {
    variables = {
      API_GATEWAY_URL = aws_api_gateway_deployment.webhook_deployment.invoke_url
    }
  }
}

