  })
}

resource "aws_iam_role_policy_attachment" "codebuild_s3_access" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_github_access" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeCommitPowerUser"
}

resource "aws_codebuild_source_credential" "github_credential" {
  server_type = "GITHUB"
  auth_type   = "PERSONAL_ACCESS_TOKEN"
  token       = var.github_personal_access_token # Replace with variable or secret
}

resource "aws_codebuild_project" "autograding" {
  name          = "autograding-system-${random_id.suffix.hex}"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image          = "aws/codebuild/standard:6.0"
    type           = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "OUTPUT_BUCKET"
      value = aws_s3_bucket.autograding_outputs.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO"
      value = var.github_repo # Replace with variable or secret
    }
  }

  source {
    type      = "GITHUB"
    location  = var.github_repo # Replace with variable or secret
    git_clone_depth = 1
  }

  cache {
    type     = "LOCAL"
    modes    = ["LOCAL_DOCKER_LAYER_CACHE", "LOCAL_SOURCE_CACHE"]
  }

  logs_config {
    cloudwatch_logs {
      stream_name   = "autograding-logs"
      group_name    = "/aws/codebuild/autograding-system"
    }
  }
}

resource "aws_cloudwatch_log_group" "autograding" {
  name              = "/aws/codebuild/autograding-system"
  retention_in_days = 7
}

resource "aws_s3_bucket_notification" "autograding_outputs" {
  bucket = aws_s3_bucket.autograding_outputs.id

  lambda_function {
    lambda_function_arn = aws_lambda_function.grading_complete.arn
    events              = ["s3:ObjectCreated:*"]
    filter_suffix       = ".json"
  }

  depends_on = [aws_lambda_permission.allow_bucket]
}

resource "aws_lambda_function" "grading_complete" {
  filename      = "lambda_function.zip"
  function_name = "grading-complete-handler"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  environment {
    variables = {
      OUTPUT_BUCKET = aws_s3_bucket.autograding_outputs.bucket
    }
  }
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = ["lambda.amazonaws.com"]
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_s3_access" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

resource "aws_lambda_permission" "allow_bucket" {
  statement_id  = "AllowExecutionFromS3Bucket"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.grading_complete.function_name
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.autograding_outputs.arn
}

resource "aws_s3_bucket_public_access_block" "autograding_outputs" {
  bucket = aws_s3_bucket.autograding_outputs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}
```

