  name          = "autograding-${random_id.suffix.hex}"
  description   = "Autograding system for student submissions"
  service_role  = aws_iam_role.codebuild_role.arn
  build_timeout = "60"

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type            = "LINUX_CONTAINER"
    privileged_mode = true

    environment_variable {
      name  = "SUBMISSION_BUCKET"
      value = aws_s3_bucket.submissions.bucket
    }

    environment_variable {
      name  = "GITHUB_REPO_OWNER"
      value = var.github_repo_owner
    }

    environment_variable {
      name  = "GITHUB_REPO_NAME"
      value = var.github_repo_name
    }

    environment_variable {
      name  = "GITHUB_BRANCH"
      value = var.github_branch
    }

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = var.github_token
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/${var.github_repo_owner}/${var.github_repo_name}.git"
    git_clone_depth = 1
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install requests boto3
        pre_build:
          commands:
            - echo "Fetching latest submissions..."
            - aws s3 sync s3://${SUBMISSION_BUCKET}/submissions/ ./submissions
        build:
          commands:
            - echo "Starting autograding..."
            - |
              for submission in submissions/*; do
                echo "Processing submission: $submission"
                # Extract filename from path
                filename=$(basename "$submission")
                # Create a temporary directory for the submission
                temp_dir=$(mktemp -d)
                cp "$submission" "$temp_dir/"
                cd "$temp_dir"
                # Run the submission with no internet access
                timeout 300 python3 -c "
                import os
                import sys
                import socket
                socket.setdefaulttimeout(1)
                try:
                    socket.create_connection(('1.1.1.1', 53))
                    print('ERROR: Internet access detected!', file=sys.stderr)
                    sys.exit(1)
                except:
                    pass
                # Execute the submission
                import subprocess
                result = subprocess.run(['python3', '$filename'], capture_output=True, text=True)
                print('STDOUT:', result.stdout)
                print('STDERR:', result.stderr)
                print('Return code:', result.returncode)
                " > output.txt
                # Upload results to S3
                aws s3 cp output.txt s3://${SUBMISSION_BUCKET}/results/${filename}.txt
                rm -rf "$temp_dir"
              done
      EOT
  }

  tags = {
    Name = "autograding-codebuild-${random_id.suffix.hex}"
  }
}

# IAM role for CodeBuild
resource "aws_iam_role" "codebuild_role" {
  name = "autograding-codebuild-role-${random_id.suffix.hex}"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_service" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSCodeBuildServiceRole"
}

resource "aws_iam_role_policy" "codebuild_s3_access" {
  name = "autograding-codebuild-s3-access"
  role = aws_iam_role.codebuild_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ],
        Effect   = "Allow",
        Resource = [
          aws_s3_bucket.submissions.arn,
          "${aws_s3_bucket.submissions.arn}/*"
        ]
      },
      {
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Effect   = "Allow",
        Resource = "*"
      }
    ]
  })
}

# Lambda function to trigger CodeBuild on GitHub push
resource "aws_lambda_function" "github_webhook" {
  function_name = "autograding-github-webhook-${random_id.suffix.hex}"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.lambda_handler"
  runtime       = "python3.8"
  filename      = "data/autograding_webhook.zip"
  timeout       = 30

  environment {
    variables = {
      CODEBUILD_PROJECT = aws_codebuild_project.autograding.name
      SUBMISSION_BUCKET = aws_s3_bucket.submissions.bucket
    }
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "autograding-lambda-role-${random_id.suffix.hex}"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_basic" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_iam_role_policy" "lambda_codebuild_access" {
  name = "autograding-lambda-codebuild-access"
  role = aws_iam_role.lambda_role.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "codebuild:BatchGetBuilds",
          "codebuild:StartBuild"
        ],
        Effect   = "Allow",
        Resource = aws_codebuild_project.autograding.arn
      },
      {
        Action = [
          "s3:PutObject"
        ],
        Effect   = "Allow",
        Resource = "${aws_s3_bucket.submissions.arn}/*"
      }
    ]
  })
}

# API Gateway to receive GitHub webhook
resource "aws_api_gateway_rest_api" "github_webhook" {
  name = "autograding-github-webhook-${random_id.suffix.hex}"
}

resource "aws_api_gateway_resource" "webhook" {
  rest_api_id = aws_api_gateway_rest_api.github_webhook.id
  parent_id   = aws_api_gateway_rest_api.github_webhook.root_resource_id
  path_part   = "webhook"
}

resource "aws_api_gateway_method" "post" {
  rest_api_id   = aws_api_gateway_rest_api.github_webhook.id
  resource_id   = aws_api_gateway_resource.webhook.id
  http_method   = "POST"
  authorization = "NONE"
}

resource "aws_api_gateway_integration" "lambda" {
  rest_api_id = aws_api_gateway_rest_api.github_webhook.id
  resource_id = aws_api_gateway_resource.webhook.id
  http_method = aws_api_gateway_method.post.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.github_webhook.invoke_arn
}

resource "aws_lambda_permission" "apigw" {
  statement_id  = "AllowAPIGatewayInvoke"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.github_webhook.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.github_webhook.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "deployment" {
  depends_on = [aws_api_gateway_integration.lambda]
  rest_api_id = aws_api_gateway_rest_api.github_webhook.id
  stage_name  = "prod"
}

# CloudWatch Event Rule to trigger Lambda on GitHub push
resource "aws_cloudwatch_event_rule" "github_push" {
  name                = "autograding-github-push-${random_id.suffix.hex}"
  description         = "Trigger on GitHub push events"
  schedule_expression = "rate(1 minute)"
}

resource "aws_cloudwatch_event_target" "lambda" {
  rule      = aws_cloudwatch_event_rule.github_push.name
  target_id = "TriggerLambda"
  arn       = aws_lambda_function.github_webhook.arn
}

# Data sources
data "aws_availability_zones" "available" {
  state = "available"
}

# Outputs
output "api_gateway_url" {
  description = "URL of the API Gateway endpoint for GitHub webhook"
  value       = "${aws_api_gateway_deployment.deployment.invoke_url}/webhook"
}

output "codebuild_project_name" {
  description = "Name of the CodeBuild project"
  value       = aws_codebuild_project.autograding.name
}

output "submission_bucket_name" {
  description = "Name of the S3 bucket for submissions"
  value       = aws_s3_bucket.submissions.bucket
}
