}

# Create CodeBuild project
resource "aws_codebuild_project" "autograding" {
  name          = "${var.course_config.environment_name}-autograding-project"
  description   = "Autograding system for ${var.course_config.name}"
  build_timeout = "60"

  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/amazonlinux2-x86_64-standard:4.0"
    type                        = "LINUX_CONTAINER"
    image_pull_credentials_type = "CODEBUILD"
    privileged_mode             = true

    environment_variable {
      name  = "STUDENT_CODE_BUCKET"
      value = var.course_config.student_code_bucket_name
    }

    environment_variable {
      name  = "RESULTS_BUCKET"
      value = var.course_config.results_bucket_name
    }

    environment_variable {
      name  = "GITHUB_REPO_OWNER"
      value = var.github_repo.owner
    }

    environment_variable {
      name  = "GITHUB_REPO_NAME"
      value = var.github_repo.repo_name
    }

    environment_variable {
      name  = "GITHUB_BRANCH"
      value = var.github_repo.branch
    }

    environment_variable {
      name  = "GITHUB_OAUTH_TOKEN"
      value = var.github_repo.oauth_token
    }

    environment_variable {
      name  = "CODEBUILD_WORKSPACE"
      value = "/codebuild/output"
    }

    environment_variable {
      name  = "CODEBUILD_SRC_DIR"
      value = "/codebuild/src"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/${var.github_repo.owner}/${var.github_repo.repo_name}.git"
    git_clone_depth = 1
    git_submodules_config {
      fetch_submodules = true
    }
    buildspec = <<-EOT
      version: 0.2
      phases:
        install:
          runtime-versions:
            python: 3.8
          commands:
            - echo "Installing dependencies..."
            - pip install boto3 requests
        pre_build:
          commands:
            - echo "Fetching student submissions..."
            - aws s3 cp s3://${var.course_config.student_code_bucket_name}/student-submissions.zip /codebuild/src/
            - unzip /codebuild/src/student-submissions.zip -d /codebuild/src
            - mkdir -p /codebuild/output/results
        build:
          commands:
            - echo "Starting autograding..."
            - python3 /codebuild/src/autograder.py
        post_build:
          commands:
            - echo "Uploading results..."
            - aws s3 cp /codebuild/output/results s3://${var.course_config.results_bucket_name}/ --recursive
      artifacts:
        files: '**/*'
      cache:
        paths: '/root/.cache/pip/**/*'
    EOT
  }

  network_config {
    vpc_id     = aws_vpc.autograding.id
    subnets    = aws_subnet.private[*].id
    security_groups = [aws_security_group.codebuild.id]
  }
}

# Create a VPC endpoint for S3 to enable private access
resource "aws_vpc_endpoint" "s3" {
  vpc_id            = aws_vpc.autograding.id
  service_name      = "com.amazonaws.${data.aws_region.current.name}.s3"
  vpc_endpoint_type = "Gateway"

  route_table_ids = [aws_route_table.private.id]
}

# Get current AWS region
data "aws_region" "current" {}

