  name = "caas_lambda_exec_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_s3_access" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

resource "aws_iam_role_policy_attachment" "lambda_dynamodb_access" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonDynamoDBFullAccess"
}

resource "aws_lambda_function" "caas_get" {
  function_name = "caas_get"
  role          = aws_iam_role.lambda_exec.arn
  runtime       = "python3.8"
  handler       = "index.handler"
  s3_bucket     = aws_s3_bucket.cat_images.bucket
  s3_key        = "lambda/caas_get.zip"
  environment {
    variables = {
      CAT_IMAGES_BUCKET = aws_s3_bucket.cat_images.bucket
      CAT_TABLE_NAME    = aws_dynamodb_table.cats.name
    }
  }
}

resource "aws_lambda_function" "caas_put" {
  function_name = "caas_put"
  role          = aws_iam_role.lambda_exec.arn
  runtime       = "python3.8"
  handler       = "index.handler"
  s3_bucket     = aws_s3_bucket.cat_images.bucket
  s3_key        = "lambda/caas_put.zip"
  environment {
    variables = {
      CAT_IMAGES_BUCKET = aws_s3_bucket.cat_images.bucket
      CAT_TABLE_NAME    = aws_dynamodb_table.cats.name
    }
  }
}

resource "aws_dynamodb_table" "cats" {
  name           = "caas-cats"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "name"

  attribute {
    name = "name"
    type = "S"
  }
}

resource "aws_apigatewayv2_api" "caas" {
  name          = "caas"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_integration" "caas_get" {
  api_id             = aws_apigatewayv2_api.caas.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.caas_get.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_integration" "caas_put" {
  api_id             = aws_apigatewayv2_api.caas.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.caas_put.invoke_arn
  integration_method = "POST"
}

resource "aws_apigatewayv2_route" "caas_get" {
  api_id    = aws_apigatewayv2_api.caas.id
  route_key = "GET /caas/cat"
  target    = "integrations/${aws_apigatewayv2_integration.caas_get.id}"
}

resource "aws_apigatewayv2_route" "caas_put" {
  api_id    = aws_apigatewayv2_api.caas.id
  route_key = "PUT /caas/cat"
  target    = "integrations/${aws_apigatewayv2_integration.caas_put.id}"
}

resource "aws_apigatewayv2_stage" "default" {
  api_id      = aws_apigatewayv2_api.caas.id
  name        = "$default"
  auto_deploy = true
}

resource "aws_lambda_permission" "apigw_caas_get" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_get.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.caas.execution_arn}/*/*"
}

resource "aws_lambda_permission" "apigw_caas_put" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_put.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_apigatewayv2_api.caas.execution_arn}/*/*"
}
