resource "random_id" "key_suffix" {
  byte_length = 4
}

resource "aws_key_pair" "ec2_key" {
  key_name   = "ec2-key-${random_id.key_suffix.hex}"
  public_key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQ..." # Replace with your actual public key
}

resource "aws_instance" "example" {
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI (us-east-1)
  instance_type = "t2.micro"
  key_name      = aws_key_pair.ec2_key.key_name

  tags = {
    Name = "example-instance"
  }
}

resource "aws_backup_vault" "example" {
  name = "example-backup-vault"
}

resource "aws_backup_plan" "example" {
  name = "example-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 0 * * ? *)" # Daily at 12:00 AM UTC
    start_window      = 60  # 60 minutes window for backup jobs
    delete_after      = 7    # Delete backups after 7 days
    lifecycle {
      move_to_cold_storage_after = 30
      cold_storage_after        = 365
    }
  }
}

resource "aws_backup_selection" "example" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "example-selection"

  resources = [
    aws_instance.example.arn
  ]

  selection_tag {
    type  = "STRING"
    key   = "Name"
    values = ["example-instance"]
  }
}

resource "aws_iam_role" "backup_role" {
  name = "backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "backup_service" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupDefaultServiceRole"
}

resource "aws_backup_plan" "example" {
  name = "example-backup-plan"

  rule {
    rule_name         = "daily-backup-rule"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 0 * * ? *)"
    start_window      = 60
    delete_after      = 7
    lifecycle {
      move_to_cold_storage_after = 30
      cold_storage_after        = 365
    }
    copy_action {
      destination_backup_vault_arn = aws_backup_vault.example.arn
      backup_vault_name           = aws_backup_vault.example.name
    }
  }
}
```

