  s3_bucket     = aws_s3_bucket.lambda_bucket.bucket
  s3_key        = aws_s3_bucket_object.lambda_function.key

  environment {
    variables = {
      LOG_LEVEL = "INFO"
    }
  }
}

resource "aws_s3_bucket" "lambda_bucket" {
  bucket = "lambda-function-bucket-${random_id.suffix.hex}"
}

resource "aws_s3_bucket_object" "lambda_function" {
  bucket = aws_s3_bucket.lambda_bucket.bucket
  key    = "daily_task.zip"
  source = "path/to/your/daily_task.zip" # Replace with actual path to your Lambda function zip file
  etag   = filemd5("path/to/your/daily_task.zip")
}

resource "aws_cloudwatch_event_rule" "daily_schedule" {
  name                = "daily-task-schedule-${random_id.suffix.hex}"
  description         = "Fires daily at 07:00 UTC"
  schedule_expression = "cron(0 7 * * ? *)"
}

resource "aws_cloudwatch_event_target" "lambda_target" {
  rule      = aws_cloudwatch_event_rule.daily_schedule.name
  target_id = "SendToLambda"
  arn       = aws_lambda_function.daily_task.arn
}

resource "aws_lambda_permission" "allow_cloudwatch" {
  statement_id  = "AllowExecutionFromCloudWatch"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.daily_task.function_name
  principal     = "events.amazonaws.com"
  source_arn    = aws_cloudwatch_event_rule.daily_schedule.arn
}
