# Generate random suffix for resource naming
resource "random_id" "suffix" {
  byte_length = 4
}

# Create S3 bucket for video storage with versioning and lifecycle policy
resource "aws_s3_bucket" "video_bucket" {
  bucket = "video-streaming-${random_id.suffix.hex}"
  force_destroy = true
}

resource "aws_s3_bucket_versioning" "video_bucket_versioning" {
  bucket = aws_s3_bucket.video_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_public_access_block" "video_bucket_public_access" {
  bucket = aws_s3_bucket.video_bucket.id

  block_public_acls       = false
  block_public_policy     = false
  ignore_public_acls      = false
  restrict_public_buckets = false
}

resource "aws_s3_bucket_policy" "video_bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id
  policy = data.aws_iam_policy_document.video_bucket_policy.json
}

data "aws_iam_policy_document" "video_bucket_policy" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.video_bucket.arn}/*"]

    principals {
      type        = "*"
      identifiers = ["*"]
    }

    condition {
      test     = "IpAddress"
      variable = "aws:SourceIp"
      values   = ["0.0.0.0/0"]
    }
  }
}

# Create CloudFront distribution for global video delivery
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_bucket.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.video_oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_bucket.id}"

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_cloudfront_origin_access_identity" "video_oai" {
  comment = "OAI for video streaming bucket"
}

# Create Route 53 hosted zone and record for the CloudFront distribution
resource "aws_route53_zone" "video_domain" {
  name = "videostreaming.example"
}

resource "aws_route53_record" "video_record" {
  zone_id = aws_route53_zone.video_domain.zone_id
  name    = aws_route53_zone.video_domain.name
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

# Create Lambda@Edge function for dynamic content processing
resource "aws_lambda_function" "video_processing" {
  filename      = "lambda_function.zip"
  function_name = "video-processing-function"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs14.x"
  timeout       = 30
}

resource "aws_iam_role" "lambda_exec" {
  name = "lambda_exec"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "lambda.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "lambda_basic_execution" {
  role       = aws_iam_role.lambda_exec.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

# Create CloudFront function for dynamic content processing
resource "aws_cloudfront_function" "video_processing_function" {
  name    = "video-processing-function"
  runtime = "cloudfront-js-1.0"
  publish = true

  code = <<CODE
function handler(event) {
  var request = event.request;
  // Add any dynamic processing logic here
  return request;
}
CODE
}

# Create CloudFront function association
resource "aws_cloudfront_function_association" "video_processing_association" {
  depends_on = [aws_cloudfront_function.video_processing_function]

  distribution_id = aws_cloudfront_distribution.video_distribution.id
  event_type      = "viewer-request"
  function_code   = aws_cloudfront_function.video_processing_function.id
}

# Create S3 bucket for video thumbnails
resource "aws_s3_bucket" "thumbnails_bucket" {
  bucket = "video-thumbnails-${random_id.suffix.hex}"
  force_destroy = true
}

# Create S3 bucket for analytics data
resource "aws_s3_bucket" "analytics_bucket" {
  bucket = "video-analytics-${random_id.suffix.hex}"
  force_destroy = true
}

# Create Kinesis Data Stream for real-time analytics
resource "aws_kinesis_stream" "video_stream" {
  name             = "video-streaming-analytics"
  shard_count      = 3
  retention_period = 24
}

# Create DynamoDB table for user preferences and watch history
resource "aws_dynamodb_table" "user_preferences" {
  name           = "VideoUserPreferences"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "userId"

  attribute {
    name = "userId"
    type = "S"
  }
}

# Create API Gateway for user management and preferences
resource "aws_apigatewayv2_api" "video_api" {
  name          = "video-streaming-api"
  protocol_type = "HTTP"
}

resource "aws_apigatewayv2_integration" "video_integration" {
  api_id             = aws_apigatewayv2_api.video_api.id
  integration_type   = "AWS_PROXY"
  integration_uri    = aws_lambda_function.user_management_function.arn
}

resource "aws_lambda_function" "user_management_function" {
  filename      = "user-management-lambda.zip"
  function_name = "user-management-function"
  role          = aws_iam_role.lambda_exec.arn
  handler       = "index.handler"
  runtime       = "nodejs14.x"
  timeout       = 30
}

# Create CloudWatch Logs for monitoring
resource "aws_cloudwatch_log_group" "video_logs" {
  name              = "/video-streaming-platform"
  retention_in_days = 30
}

# Create SNS topic for notifications
resource "aws_sns_topic" "video_notifications" {
  name = "video-streaming-notifications"
}

# Create SQS queue for processing notifications
resource "aws_sqs_queue" "video_queue" {
  name = "video-streaming-queue"
}

# Create IAM role for EC2 instances (if needed for transcoding)
resource "aws_iam_role" "transcoding_role" {
  name = "video-transcoding-role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "ec2.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
EOF
}

# Attach policies to the transcoding role
resource "aws_iam_role_policy_attachment" "transcoding_s3_access" {
  role       = aws_iam_role.transcoding_role.name
  policy_arn = aws_iam_policy.transcoding_s3_access.arn
}

resource "aws_iam_policy" "transcoding_s3_access" {
  name        = "transcoding-s3-access"
  description = "Policy for S3 access for transcoding"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "s3:GetObject",
        "s3:PutObject",
        "s3:DeleteObject"
      ],
      "Resource": [
        "${aws_s3_bucket.video_bucket.arn}/*",
        "${aws_s3_bucket.thumbnails_bucket.arn}/*"
      ]
    }
  ]
}
EOF
}

