# main.tf
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC Module
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b", "us-east-1c"]
  public_subnets  = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  private_subnets = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]

  enable_nat_gateway   = true
  single_nat_gateway   = true
  enable_dns_hostnames = true

  tags = {
    Terraform   = "true"
    Environment = "production"
  }
}

# Security Groups
resource "aws_security_group" "allow_web_traffic" {
  name        = "allow_web_traffic"
  description = "Allow HTTP/HTTPS traffic"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description = "HTTP from anywhere"
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    description = "HTTPS from anywhere"
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_web_traffic"
  }
}

resource "aws_security_group" "allow_ssh" {
  name        = "allow_ssh"
  description = "Allow SSH traffic"
  vpc_id      = module.vpc.vpc_id

  ingress {
    description = "SSH from anywhere"
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "allow_ssh"
  }
}

# EC2 Instances for Video Servers
resource "random_id" "instance_suffix" {
  byte_length = 4
}

resource "aws_instance" "video_server" {
  count         = 3
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 AMI (us-east-1)
  instance_type = "t3.large"
  subnet_id     = module.vpc.public_subnets[count.index]
  vpc_security_group_ids = [
    aws_security_group.allow_web_traffic.id,
    aws_security_group.allow_ssh.id
  ]

  tags = {
    Name = "video-server-${count.index + 1}-${random_id.instance_suffix.hex}"
  }

  user_data = <<-EOF
              #!/bin/bash
              yum update -y
              yum install -y httpd
              systemctl start httpd
              systemctl enable httpd
              EOF
}

# Elastic Load Balancer
resource "aws_lb" "video_streaming_lb" {
  name               = "video-streaming-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.allow_web_traffic.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Environment = "production"
  }
}

resource "aws_lb_target_group" "video_streaming_tg" {
  name     = "video-streaming-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200-299"
  }
}

resource "aws_lb_listener" "video_streaming_listener" {
  load_balancer_arn = aws_lb.video_streaming_lb.arn
  port              = 80
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  }
}

resource "aws_lb_target_group_attachment" "video_server_attachment" {
  count            = length(aws_instance.video_server)
  target_group_arn = aws_lb_target_group.video_streaming_tg.arn
  target_id        = aws_instance.video_server[count.index].id
  port             = 80
}

# Route 53
resource "aws_route53_zone" "video_streaming" {
  name = "video.example.com"
}

resource "aws_route53_record" "video_streaming" {
  zone_id = aws_route53_zone.video_streaming.zone_id
  name    = "video.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.video_streaming_lb.dns_name
    zone_id                = aws_lb.video_streaming_lb.zone_id
    evaluate_target_health = true
  }
}

# S3 Bucket for Static Content
resource "aws_s3_bucket" "video_content" {
  bucket = "video-content-bucket-${random_id.instance_suffix.hex}"
  acl    = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "Video Content Bucket"
    Environment = "Production"
  }
}

# CloudFront Distribution for CDN
resource "aws_cloudfront_distribution" "video_streaming_cdn" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.bucket}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.cdn_origin_access.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.bucket}"

    forwarded_values {
      query_string = false

      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }
}

resource "aws_cloudfront_origin_access_identity" "cdn_origin_access" {
  comment = "Access identity for video content bucket"
}

# DynamoDB for Tracking View Counts
resource "aws_dynamodb_table" "view_counts" {
  name           = "VideoViewCounts"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "video_id"

  attribute {
    name = "video_id"
    type = "S"
  }

  tags = {
    Name = "VideoViewCounts"
  }
}

# CloudWatch Logs for Monitoring
resource "aws_cloudwatch_log_group" "video_streaming_logs" {
  name              = "/video-streaming-platform"
  retention_in_days = 30
}

# IAM Role for EC2 Instances
resource "aws_iam_role" "video_server_role" {
  name = "video-server-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "video_server_ssm" {
  role       = aws_iam_role.video_server_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "video_server_profile" {
  name = "video-server-profile"
  role = aws_iam_role.video_server_role.name
}

# Outputs
output "dns_name" {
  value = aws_route53_record.video_streaming.fqdn
}

output "load_balancer_dns" {
  value = aws_lb.video_streaming_lb.dns_name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.video_content.bucket
}

output "cloudfront_domain" {
  value = aws_cloudfront_distribution.video_streaming_cdn.domain_name
}

