resource "aws_cloudfront_origin_access_identity" "cdn_origin_access" {
  comment = "Access identity for video content bucket"
}

# DynamoDB for Tracking View Counts
resource "aws_dynamodb_table" "view_counts" {
  name           = "VideoViewCounts"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "video_id"

  attribute {
    name = "video_id"
    type = "S"
  }

  tags = {
    Name = "VideoViewCounts"
  }
}

# CloudWatch Logs for Monitoring
resource "aws_cloudwatch_log_group" "video_streaming_logs" {
  name              = "/video-streaming-platform"
  retention_in_days = 30
}

# IAM Role for EC2 Instances
resource "aws_iam_role" "video_server_role" {
  name = "video-server-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "video_server_ssm" {
  role       = aws_iam_role.video_server_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "video_server_profile" {
  name = "video-server-profile"
  role = aws_iam_role.video_server_role.name
}

# Outputs
output "dns_name" {
  value = aws_route53_record.video_streaming.fqdn
}

output "load_balancer_dns" {
  value = aws_lb.video_streaming_lb.dns_name
}

output "s3_bucket_name" {
  value = aws_s3_bucket.video_content.bucket
}

output "cloudfront_domain" {
  value = aws_cloudfront_distribution.video_streaming_cdn.domain_name
}
