resource "random_id" "suffix" {
  byte_length = 4
}

resource "random_password" "db" {
  length  = 20
  special = true
}

resource "aws_vpc" "custom_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "custom-postgres-vpc"
  }
}

resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.custom_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "private-postgres-subnet"
  }
}

resource "aws_db_subnet_group" "private_subnet_group" {
  name       = "private-postgres-subnet-group"
  subnet_ids = [aws_subnet.private_subnet.id]

  tags = {
    Name = "PostgreSQL Subnet Group"
  }
}

resource "aws_security_group" "postgres_sg" {
  name        = "postgres-security-group"
  description = "Allow PostgreSQL access"
  vpc_id      = aws_vpc.custom_vpc.id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24"] # Restrict to private subnet
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL Security Group"
  }
}

resource "aws_db_instance" "postgres" {
  identifier             = "postgres-${random_id.suffix.hex}"
  allocated_storage      = 20
  engine                 = "postgres"
  engine_version         = "13.4"
  instance_class         = "db.t3.micro"
  db_name                = "postgresdb"
  username               = "postgresadmin"
  password               = random_password.db.result
  skip_final_snapshot    = true
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  db_subnet_group_name   = aws_db_subnet_group.private_subnet_group.name
  publicly_accessible    = false
  storage_encrypted      = true
  backup_retention_period = 7
  multi_az               = false
}
```

