  password               = random_password.db.result
  parameter_group_name   = "default.postgres13"
  skip_final_snapshot    = true
  publicly_accessible    = false
  db_subnet_group_name   = aws_db_subnet_group.private_subnet_group.name
  vpc_security_group_ids = [aws_security_group.postgres_sg.id]
  storage_encrypted      = true
  backup_retention_period = 7
  multi_az               = false # Set to true if high availability is required

  # Enable major version upgrades and minor version auto-updates
  apply_immediately       = true
  auto_minor_version_upgrade = true
  maintenance_window      = "sun:03:00-sun:05:00"
  preferred_maintenance_window = "Sun:03:00-Sun:05:00"
}

resource "aws_security_group" "postgres_sg" {
  name        = "postgres-sg"
  description = "Allow PostgreSQL access within VPC"
  vpc_id      = aws_vpc.custom_vpc.id

  ingress {
    description = "PostgreSQL access from within VPC"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = [aws_vpc.custom_vpc.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "PostgreSQL Security Group"
  }
}
```

