```hcl
# Create VPC
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true
  tags = {
    Name = "aurora-mysql-vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "aurora_igw" {
  vpc_id = aws_vpc.aurora_vpc.id
  tags = {
    Name = "aurora-mysql-igw"
  }
}

# Create Subnets
resource "aws_subnet" "aurora_private_subnet" {
  count             = 2
  vpc_id            = aws_vpc.aurora_vpc.id
  cidr_block        = "10.0.${count.index}.0/24"
  availability_zone = element(["us-east-1a", "us-east-1b"], count.index)
  tags = {
    Name = "aurora-mysql-private-subnet-${count.index}"
  }
}

# Create Route Table
resource "aws_route_table" "aurora_route_table" {
  vpc_id = aws_vpc.aurora_vpc.id
  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.aurora_igw.id
  }
  tags = {
    Name = "aurora-mysql-route-table"
  }
}

# Associate Route Table with Subnets
resource "aws_route_table_association" "aurora_route_association" {
  count          = 2
  subnet_id      = aws_subnet.aurora_private_subnet[count.index].id
  route_table_id = aws_route_table.aurora_route_table.id
}

# Create Security Group for Aurora Cluster
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-mysql-sg"
  description = "Allow MySQL traffic"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-mysql-sg"
  }
}

# Create Subnet Group for Aurora Cluster
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-mysql-subnet-group"
  subnet_ids = aws_subnet.aurora_private_subnet[*].id
  tags = {
    Name = "aurora-mysql-subnet-group"
  }
}

# Create Aurora MySQL Cluster
resource "random_id" "db_cluster_suffix" {
  byte_length = 4
}

resource "aws_rds_cluster" "aurora_mysql" {
  cluster_identifier      = "aurora-mysql-cluster-${random_id.db_cluster_suffix.hex}"
  engine                  = "aurora-mysql"
  engine_mode             = "provisioned"
  database_name           = "auroradb"
  master_username         = "admin"
  master_password         = random_password.db_password.result
  backup_retention_period = 7
  preferred_backup_window = "07:00-09:00"
  storage_encrypted       = true
  enable_http_endpoint    = true
  skip_final_snapshot     = true

  engine_version          = "8.0.mysql_aurora.3.08.0"
  db_cluster_parameter_group_name = aws_db_parameter_group.aurora_mysql.name
  db_subnet_group_name    = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids  = [aws_security_group.aurora_sg.id]

  tags = {
    Name = "aurora-mysql-cluster"
  }
}

# Create Aurora MySQL Parameter Group
resource "aws_db_parameter_group" "aurora_mysql" {
  name        = "aurora-mysql-parameter-group"
  family      = "aurora-mysql8.0"
  description = "Parameter group for Aurora MySQL"
}

# Create Aurora MySQL Instance
resource "aws_rds_cluster_instance" "aurora_mysql_instance" {
  cluster_identifier = aws_rds_cluster.aurora_mysql.id
  instance_class     = "db.serverless"
  engine             = aws_rds_cluster.aurora_mysql.engine
  engine_version     = aws_rds_cluster.aurora_mysql.engine_version
}

# Create Random Password for Database
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!#$%&*()-_=+[]{}<>:?"
}

# Create IAM Role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Create IAM Policy for RDS Proxy
resource "aws_iam_policy" "rds_proxy_policy" {
  name        = "rds-proxy-policy"
  description = "Policy for RDS Proxy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "secretsmanager:GetSecretValue"
        ],
        Effect   = "Allow",
        Resource = aws_secretsmanager_secret.db_secret.arn
      }
    ]
  })
}

# Attach IAM Policy to Role
resource "aws_iam_role_policy_attachment" "rds_proxy_attachment" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = aws_iam_policy.rds_proxy_policy.arn
}

# Create RDS Proxy
resource "aws_db_proxy" "rds_proxy" {
  name                   = "aurora-mysql-proxy"
  engine_family          = "MYSQL"
  require_tls            = true
  role_arn               = aws_iam_role.rds_proxy_role.arn
  vpc_security_group_ids = [aws_security_group.aurora_sg.id]
  secrets_proxy_arn      = aws_secretsmanager_secret.db_secret.arn
  tags = {
    Name = "aurora-mysql-proxy"
  }
}

# Create Secrets Manager Secret
resource "aws_secretsmanager_secret" "db_secret" {
  name        = "aurora-mysql-secret"
  description = "Secret for Aurora MySQL"
}

# Store Database Credentials in Secrets Manager
resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id     = aws_secretsmanager_secret.db_secret.id
  secret_string = jsonencode({
    username = aws_rds_cluster.aurora_mysql.master_username
    password = aws_rds_cluster.aurora_mysql.master_password
  })
}

# Create Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Allow proxy traffic"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# Associate Security Group with RDS Proxy
resource "aws_db_proxy_default_target_group" "rds_proxy_target_group" {
  db_proxy_name = aws_db_proxy.rds_proxy.name
  target_group_name = "aurora-mysql-target-group"
  db_cluster_arns = [aws_rds_cluster.aurora_mysql.arn]
}
```

