  public_key = file("~/.ssh/id_rsa.pub") # Replace with your public key path
}

resource "aws_lightsail_access_key" "s3_access" {
  instance_name = aws_lightsail_instance.web_server.name
}

resource "aws_iam_user" "lightsail_s3_user" {
  name = "lightsail-s3-access"
  tags = {
    purpose = "Lightsail S3 Access"
  }
}

resource "aws_iam_user_policy_attachment" "s3_full_access" {
  user       = aws_iam_user.lightsail_s3_user.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_access_key" "lightsail_s3_key" {
  user = aws_iam_user.lightsail_s3_user.name
}

resource "aws_lightsail_instance_attachment" "s3_config" {
  instance_name = aws_lightsail_instance.web_server.name
  key_pair_name = aws_key_pair.lightsail_key.key_name
  user_data     = <<-EOF
              #!/bin/bash
              # Install AWS CLI and configure it with S3 access
              sudo apt-get update
              sudo apt-get install -y awscli
              aws configure set aws_access_key_id ${aws_iam_access_key.lightsail_s3_key.id}
              aws configure set aws_secret_access_key ${aws_iam_access_key.lightsail_s3_key.secret}
              aws configure set region us-east-1
              EOF
}

