resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_s3_bucket" "origin_bucket" {
  bucket = "my-lightsail-distribution-origin-${random_id.suffix.hex}"
  acl    = "private"
}

resource "aws_lightsail_distribution" "cdn" {
  domain_name = "example.com"
  origin {
    origin_path = aws_s3_bucket.origin_bucket.bucket_regional_domain_name
    origin_id   = "S3-Origin-${aws_s3_bucket.origin_bucket.id}"
    custom_origin_config {
      origin_protocol_policy = "http-only"
      http_port              = 80
      https_port             = 443
      origin_ssl_protocols   = ["TLSv1.2"]
    }
  }
  enabled = true
  price_plan = "cdn"
  aliases {
    alias_name = "cdn.example.com"
  }
  viewer_certificate {
    cloudfront_default_certificate = true
  }
  default_cache_behavior {
    target_origin_id = "S3-Origin-${aws_s3_bucket.origin_bucket.id}"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods = ["GET", "HEAD"]
    cached_methods = ["GET", "HEAD"]
    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }
    min_ttl       = 0
    default_ttl   = 3600
    max_ttl       = 86400
  }
}

resource "aws_s3_bucket_policy" "origin_bucket_policy" {
  bucket = aws_s3_bucket.origin_bucket.id
  policy = data.aws_iam_policy_document.origin_bucket_policy_document.json
}

data "aws_iam_policy_document" "origin_bucket_policy_document" {
  statement {
    actions   = ["s3:GetObject"]
    resources = ["${aws_s3_bucket.origin_bucket.arn}/*"]

    principals {
      type        = "*"
      identifiers = ["cloudfront.amazonaws.com"]
    }

    condition {
      test     = "StringLike"
      variable = "aws:Referer"
      values   = ["https://${aws_lightsail_distribution.cdn.distribution_domain_name}.*"]
    }
  }
}

