  policy_name = "glacier-transition-policy-${random_id.vault_suffix.hex}"

  schedule {
    schedule_expression = "cron(0 12 * * ? *)" # Runs daily at 12:00 UTC
  }

  rule {
    name         = "transition-to-glacier"
    target_vault = aws_glacier_vault.example.name
    filter_set {
      name = "s3-objects-filter"
      condition {
        test  = "prefix"
        value = "data/"
      }
    }
    transition {
      days         = 30
      storage_class = "GLACIER"
    }
    transition {
      days         = 90
      storage_class = "DEEP_ARCHIVE"
    }
    expiration {
      days = 365
    }
  }
}

