  restrict_public_buckets = true
}

resource "aws_iam_role" "glacier_notification_role" {
  name = "glacier-notification-role-${random_id.vault_suffix.hex}"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "s3.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "glacier_notification_s3_access" {
  role       = aws_iam_role.glacier_notification_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

resource "aws_s3_bucket_policy" "glacier_notification_bucket_policy" {
  bucket = aws_s3_bucket.glacier_notification_bucket.id
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          AWS = aws_iam_role.glacier_notification_role.arn
        }
        Action = [
          "s3:PutObject"
        ]
        Resource = [
          "arn:aws:s3:::${aws_s3_bucket.glacier_notification_bucket.id}/*"
        ]
      }
    ]
  })
}

resource "aws_s3_bucket_versioning" "glacier_notification_bucket_versioning" {
  bucket = aws_s3_bucket.glacier_notification_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_glacier_vault" "example" {
  vault_name = "glacier-vault-${random_id.vault_suffix.hex}"
  tags = {
    Name = "GlacierVault-${random_id.vault_suffix.hex}"
  }
}

resource "aws_lambda_function" "glacier_notification" {
  filename      = "data.zip"
  function_name = "glacier-notification-lambda-${random_id.vault_suffix.hex}"
  role          = aws_iam_role.glacier_notification_role.arn
  handler       = "index.handler"
  runtime       = "nodejs14.x"
  depends_on    = [aws_iam_role_policy_attachment.glacier_notification_s3_access]
}

resource "aws_lambda_permission" "allow_bucket" {
  statement_id  = "AllowExecutionFromS3Bucket"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.glacier_notification.arn
  principal     = "s3.amazonaws.com"
  source_arn    = aws_s3_bucket.glacier_notification_bucket.arn
}

resource "aws_glacier_vault_notification" "example" {
  vault_name = aws_glacier_vault.example.vault_name

  notification {
    events = ["ARCHIVE_RETRIEVAL_COMPLETED"]
    destination {
      s3_bucket {
        bucket = aws_s3_bucket.glacier_notification_bucket.id
        format = "JSON"
      }
    }
  }
}
```

