  subnet_id     = aws_subnet.internal.id
}

resource "aws_route" "internal_nat" {
  route_table_id         = aws_route_table.internal.id
  destination_cidr_block = "0.0.0.0/0"
  nat_gateway_id         = aws_nat_gateway.internal.id
}
