resource "aws_lb" "auth_cognito" {
  name               = "auth-cognito-lb-${random_id.suffix.hex}"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = [aws_subnet.public_subnet1.id, aws_subnet.public_subnet2.id]
}

resource "aws_security_group" "lb_sg" {
  name        = "auth-cognito-lb-sg"
  description = "Allow HTTP/HTTPS traffic to the load balancer"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_lb_listener" "auth_cognito" {
  load_balancer_arn = aws_lb.auth_cognito.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = aws_acm_certificate.cognito_ssl.arn

  default_action {
    type = "authenticate-cognito"
    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.auth_cognito.arn
      user_pool_client_id = aws_cognito_user_pool_client.auth_cognito_client.id
      user_pool_domain    = aws_cognito_user_pool_domain.auth_cognito.domain
      authentication_request_extra_params = {
        redirect_uri = "https://${aws_lb.auth_cognito.dns_name}/"
        state        = "/"
      }
    }
  }
}

resource "aws_cognito_user_pool" "auth_cognito" {
  name = "auth-cognito-pool"
}

resource "aws_cognito_user_pool_client" "auth_cognito_client" {
  name         = "auth-cognito-client"
  user_pool_id = aws_cognito_user_pool.auth_cognito.id
  generate_secret = true
  allowed_oauth_flows = [
    "code",
    "implicit"
  ]
  allowed_oauth_scopes = [
    "openid",
    "profile",
    "email"
  ]
  callback_urls      = ["https://${aws_lb.auth_cognito.dns_name}/"]
  logout_urls        = ["https://${aws_lb.auth_cognito.dns_name}/"]
  supported_identity_providers = ["COGNITO"]
}

resource "aws_cognito_user_pool_domain" "auth_cognito" {
  domain       = "auth-cognito-domain-${random_id.suffix.hex}"
  user_pool_id = aws_cognito_user_pool.auth_cognito.id
}

resource "aws_acm_certificate" "cognito_ssl" {
  domain_name       = "yourdomain.com" # Replace with your domain
  validation_method = "DNS"
  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_route53_record" "cert_validation" {
  for_each = {
    for dvo in aws_acm_certificate.cognito_ssl.domain_validation_options : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }

  allow_overwrite = true
  name            = each.value.name
  records         = [each.value.record]
  ttl             = 60
  type            = each.value.type
  zone_id         = aws_route53_zone.main.zone_id
}

resource "aws_route53_zone" "main" {
  name = "yourdomain.com" # Replace with your domain
}

resource "aws_subnet" "public_subnet1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-east-1a"
  map_public_ip_on_launch = true
}

resource "aws_subnet" "public_subnet2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-east-1b"
  map_public_ip_on_launch = true
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

