resource "aws_db_instance" "restored_from_s3" {
  identifier             = "restored-db-${random_id.suffix.hex}"
  allocated_storage      = 20
  engine                 = "mysql"
  instance_class         = "db.t2.micro"
  skip_final_snapshot    = true
  copy_tags_to_snapshot  = true

  # Use snapshot from S3 (requires pre-uploaded snapshot file)
  snapshot_identifier = "arn:aws:s3:::your-bucket-name/path/to/snapshot-file.sql.gz"

  # Optional: Configure backup window and maintenance window
  backup_window          = "03:00-06:00"
  maintenance_window     = "Sun:00:00-Sun:03:00"

  # Optional: Enable performance insights
  performance_insights_enabled = true
  performance_insights_retention_period = 7

  # Optional: Enable automatic minor version upgrades
  apply_immediately = true
  auto_minor_version_upgrade = true
}

resource "aws_s3_bucket" "snapshot_bucket" {
  bucket = "your-bucket-name-for-snapshots"
}

resource "aws_s3_bucket_versioning" "snapshot_bucket_versioning" {
  bucket = aws_s3_bucket.snapshot_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_iam_role" "rds_s3_access_role" {
  name = "rds-s3-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "s3_read_access" {
  role       = aws_iam_role.rds_s3_access_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

resource "aws_db_instance" "restored_from_s3_with_role" {
  identifier             = "restored-db-with-role-${random_id.suffix.hex}"
  allocated_storage      = 20
  engine                 = "mysql"
  instance_class         = "db.t2.micro"
  skip_final_snapshot    = true
  copy_tags_to_snapshot  = true
  snapshot_identifier    = "arn:aws:s3:::your-bucket-name/path/to/snapshot-file.sql.gz"
  iam_database_authentication_enabled = true

  # Attach the IAM role for S3 access
  db_cluster_parameter_group_name = aws_db_cluster_parameter_group.rds_s3_access.name

  # Optional: Configure backup window and maintenance window
  backup_window          = "03:00-06:00"
  maintenance_window     = "Sun:00:00-Sun:03:00"
}

